import requests
import json
import os
from typing import Dict, List, Optional
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry

class KongConfigurator:
    def __init__(self, kong_admin_url: str, admin_token: str = None):
        self.kong_admin_url = kong_admin_url.rstrip('/')
        self.session = requests.Session()
        
        # Configure retry strategy
        retry_strategy = Retry(
            total=3,
            backoff_factor=1,
            status_forcelist=[429, 500, 502, 503, 504],
        )
        adapter = HTTPAdapter(max_retries=retry_strategy)
        self.session.mount("http://", adapter)
        self.session.mount("https://", adapter)
        
        # Set authentication
        if admin_token:
            self.session.headers.update({'X-Consumer-Token': admin_token})
    
    def _make_request(self, method: str, endpoint: str, data: Dict = None, 
                     headers: Dict = None) -> requests.Response:
        url = f"{self.kong_admin_url}/{endpoint.lstrip('/')}"
        request_headers = headers or {}
        
        if data:
            request_headers['Content-Type'] = 'application/json'
        
        response = self.session.request(
            method=method,
            url=url,
            json=data,
            headers=request_headers,
            timeout=30
        )
        
        response.raise_for_status()
        return response
    
    def create_service(self, name: str, url: str, 
                      protocol: str = 'http', 
                      host: str = None,
                      port: int = None,
                      path: str = None) -> Dict:
        service_data = {
            'name': name,
            'url': url,
            'protocol': protocol
        }
        
        if host:
            service_data['host'] = host
        if port:
            service_data['port'] = port
        if path:
            service_data['path'] = path
            
        response = self._make_request('POST', '/services', service_data)
        return response.json()
    
    def create_route(self, service_id: str, 
                    paths: List[str] = None,
                    hosts: List[str] = None,
                    methods: List[str] = None,
                    name: str = None) -> Dict:
        route_data = {
            'service': {'id': service_id}
        }
        
        if name:
            route_data['name'] = name
        if paths:
            route_data['paths'] = paths
        if hosts:
            route_data['hosts'] = hosts
        if methods:
            route_data['methods'] = methods
            
        response = self._make_request('POST', '/routes', route_data)
        return response.json()
    
    def create_upstream(self, name: str, 
                       algorithm: str = 'round-robin',
                       slots: int = 10000) -> Dict:
        upstream_data = {
            'name': name,
            'algorithm': algorithm,
            'slots': slots
        }
        
        response = self._make_request('POST', '/upstreams', upstream_data)
        return response.json()
    
    def create_target(self, upstream_id: str, target: str, 
                     port: int = None, weight: int = 100) -> Dict:
        target_data = {
            'upstream': {'id': upstream_id},
            'target': target,
            'weight': weight
        }
        
        if port:
            target_data['port'] = port
            
        response = self._make_request('POST', '/targets', target_data)
        return response.json()
    
    def get_service(self, service_id: str) -> Dict:
        response = self._make_request('GET', f'/services/{service_id}')
        return response.json()
    
    def get_route(self, route_id: str) -> Dict:
        response = self._make_request('GET', f'/routes/{route_id}')
        return response.json()
    
    def get_upstream(self, upstream_id: str) -> Dict:
        response = self._make_request('GET', f'/upstreams/{upstream_id}')
        return response.json()
    
    def delete_service(self, service_id: str) -> bool:
        try:
            self._make_request('DELETE', f'/services/{service_id}')
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                return False
            raise
    
    def delete_route(self, route_id: str) -> bool:
        try:
            self._make_request('DELETE', f'/routes/{route_id}')
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                return False
            raise
    
    def delete_upstream(self, upstream_id: str) -> bool:
        try:
            self._make_request('DELETE', f'/upstreams/{upstream_id}')
            return True
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                return False
            raise

def main():
    # Load configuration from environment variables
    kong_admin_url = os.getenv('KONG_ADMIN_URL', 'http://localhost:8001')
    admin_token = os.getenv('KONG_ADMIN_TOKEN')
    
    # Initialize configurator
    kong = KongConfigurator(kong_admin_url, admin_token)
    
    try:
        # Create a service
        service = kong.create_service(
            name='my-service',
            url='http://httpbin.org'
        )
        print(f"Created service: {service['name']}")
        
        # Create a route
        route = kong.create_route(
            service_id=service['id'],
            paths=['/api/*'],
            hosts=['example.com']
        )
        print(f"Created route: {route['name']}")
        
        # Create upstream
        upstream = kong.create_upstream(
            name='my-upstream'
        )
        print(f"Created upstream: {upstream['name']}")
        
        # Create targets
        target1 = kong.create_target(
            upstream_id=upstream['id'],
            target='127.0.0.1',
            port=8080,
            weight=100
        )
        print(f"Created target: {target1['target']}")
        
        target2 = kong.create_target(
            upstream_id=upstream['id'],
            target='127.0.0.1',
            port=8081,
            weight=100
        )
        print(f"Created target: {target2['target']}")
        
    except Exception as e:
        print(f"Error configuring Kong: {str(e)}")

if __name__ == '__main__':
    main()